    // 필수 필드
    market: 'KRW-BTC', // 마켓 ID
    side: 'bid',       // 주문 종류 (매수: bid, 매도: ask)
    duration: '3600',  // 주문 시간 (총 3600초 = 1시간)
    frequency: '60',   // 주문 간격 (60초마다 분할 주문)

    // 조건부 필수 필드 (매수 시 price, 매도 시 volume 필수)
